### Services/IndexedDbService.cs
This service wraps JS interop calls to IndexedDB. It stores/retrieves Sites and Inspections as JSON.

```csharp
namespace SiteInspector.Services;

using Microsoft.JSInterop;
using SiteInspector.Models;
using System.Text.Json;

public class IndexedDbService
{
    private readonly IJSRuntime _js;
    private readonly JsonSerializerOptions _jsonOptions = new() { PropertyNamingPolicy = JsonNamingPolicy.CamelCase };

    public IndexedDbService(IJSRuntime js) => _js = js;

    // Sites
    public async Task<List<Site>> GetAllSitesAsync()
    {
        var json = await _js.InvokeAsync<string>("indexedDb.getAll", "sites");
        return JsonSerializer.Deserialize<List<Site>>(json, _jsonOptions) ?? new();
    }

    public async Task<Site?> GetSiteAsync(string id)
    {
        var json = await _js.InvokeAsync<string>("indexedDb.get", "sites", id);
        return string.IsNullOrEmpty(json) ? null : JsonSerializer.Deserialize<Site>(json, _jsonOptions);
    }

    public async Task SaveSiteAsync(Site site)
    {
        var json = JsonSerializer.Serialize(site, _jsonOptions);
        await _js.InvokeVoidAsync("indexedDb.put", "sites", json);
    }

    public async Task DeleteSiteAsync(string id)
    {
        await _js.InvokeVoidAsync("indexedDb.delete", "sites", id);
    }

    // Inspections
    public async Task<List<Inspection>> GetInspectionsForSiteAsync(string siteId)
    {
        var json = await _js.InvokeAsync<string>("indexedDb.getByIndex", "inspections", "siteId", siteId);
        return JsonSerializer.Deserialize<List<Inspection>>(json, _jsonOptions) ?? new();
    }

    public async Task<Inspection?> GetInspectionAsync(string id)
    {
        var json = await _js.InvokeAsync<string>("indexedDb.get", "inspections", id);
        return string.IsNullOrEmpty(json) ? null : JsonSerializer.Deserialize<Inspection>(json, _jsonOptions);
    }

    public async Task SaveInspectionAsync(Inspection inspection)
    {
        var json = JsonSerializer.Serialize(inspection, _jsonOptions);
        await _js.InvokeVoidAsync("indexedDb.put", "inspections", json);
    }

    public async Task DeleteInspectionAsync(string id)
    {
        await _js.InvokeVoidAsync("indexedDb.delete", "inspections", id);
    }

    public async Task<List<Inspection>> GetUnsyncedInspectionsAsync()
    {
        var json = await _js.InvokeAsync<string>("indexedDb.getByIndex", "inspections", "isSynced", false);
        return JsonSerializer.Deserialize<List<Inspection>>(json, _jsonOptions) ?? new();
    }
}
```

### Services/ConnectivityService.cs
Tracks online/offline status via JS interop events.

```csharp
namespace SiteInspector.Services;

using Microsoft.JSInterop;

public class ConnectivityService : IAsyncDisposable
{
    private readonly IJSRuntime _js;
    private DotNetObjectReference<ConnectivityService>? _dotNetRef;
    public bool IsOnline { get; private set; } = true;
    public event Action<bool>? OnConnectivityChanged;

    public ConnectivityService(IJSRuntime js) => _js = js;

    public async Task InitializeAsync()
    {
        _dotNetRef = DotNetObjectReference.Create(this);
        IsOnline = await _js.InvokeAsync<bool>("connectivity.initialize", _dotNetRef);
    }

    [JSInvokable]
    public void UpdateStatus(bool isOnline)
    {
        IsOnline = isOnline;
        OnConnectivityChanged?.Invoke(isOnline);
    }

    public async ValueTask DisposeAsync()
    {
        if (_dotNetRef != null)
        {
            await _js.InvokeVoidAsync("connectivity.dispose");
            _dotNetRef.Dispose();
        }
    }
}
```

### Services/SyncService.cs
Background sync when connectivity returns.

```csharp
namespace SiteInspector.Services;

public class SyncService : IDisposable
{
    private readonly IndexedDbService _db;
    private readonly ConnectivityService _connectivity;
    private readonly HttpClient _http;
    private readonly ILogger<SyncService> _logger;

    public int PendingSyncCount { get; private set; }
    public bool IsSyncing { get; private set; }
    public event Action? OnSyncStateChanged;

    public SyncService(IndexedDbService db, ConnectivityService connectivity, HttpClient http, ILogger<SyncService> logger)
    {
        _db = db;
        _connectivity = connectivity;
        _http = http;
        _logger = logger;
        _connectivity.OnConnectivityChanged += HandleConnectivityChanged;
    }

    private async void HandleConnectivityChanged(bool isOnline)
    {
        if (isOnline)
            await SyncAsync();
    }

    public async Task SyncAsync()
    {
        if (IsSyncing || !_connectivity.IsOnline) return;

        IsSyncing = true;
        OnSyncStateChanged?.Invoke();

        try
        {
            var unsynced = await _db.GetUnsyncedInspectionsAsync();
            PendingSyncCount = unsynced.Count;
            OnSyncStateChanged?.Invoke();

            foreach (var inspection in unsynced)
            {
                try
                {
                    // In production, POST to a real API endpoint
                    // For now, simulate sync with a delay
                    var response = await _http.PostAsJsonAsync("api/inspections/sync", inspection);

                    if (response.IsSuccessStatusCode)
                    {
                        inspection.IsSynced = true;
                        await _db.SaveInspectionAsync(inspection);
                        PendingSyncCount--;
                        OnSyncStateChanged?.Invoke();
                    }
                }
                catch (HttpRequestException)
                {
                    // Server unreachable — will retry on next sync
                    _logger.LogWarning("Failed to sync inspection {Id}, will retry", inspection.Id);
                }
            }
        }
        finally
        {
            IsSyncing = false;
            OnSyncStateChanged?.Invoke();
        }
    }

    public async Task UpdatePendingCountAsync()
    {
        var unsynced = await _db.GetUnsyncedInspectionsAsync();
        PendingSyncCount = unsynced.Count;
        OnSyncStateChanged?.Invoke();
    }

    public void Dispose()
    {
        _connectivity.OnConnectivityChanged -= HandleConnectivityChanged;
    }
}
```

