### Pages/NewInspection.razor
This is the core page — the checklist form. It must be extremely fast and responsive. Each checklist item has pass/fail/NA buttons. Tapping immediately updates state without waiting for any async operation. Auto-save happens periodically in the background.

```razor
@page "/inspections/new/{SiteId}"
@inject IndexedDbService Db
@inject NavigationManager Nav
@implements IDisposable

<div class="top-bar">
    <button class="back-btn" @onclick="GoBack">‹</button>
    <h1>New Inspection</h1>
    <button class="back-btn" style="font-size:1rem" @onclick="SaveAndComplete">✓</button>
</div>

@if (site == null)
{
    <div class="text-center mt-1 text-muted">Loading...</div>
}
else
{
    <div class="card">
        <div class="card-body">
            <div class="form-group">
                <label>Inspector Name</label>
                <input class="form-input" @bind="inspection.InspectorName" @bind:event="oninput" placeholder="Your name" />
            </div>
            <div class="form-group">
                <label>General Notes</label>
                <textarea class="form-input" @bind="inspection.Notes" @bind:event="oninput" placeholder="Overall observations..." rows="3"></textarea>
            </div>
        </div>
    </div>

    @* Progress *@
    @{
        var total = inspection.ChecklistItems.Count;
        var completed = inspection.ChecklistItems.Count(c => c.Result != CheckResult.NotChecked);
        var pct = total > 0 ? (int)(100.0 * completed / total) : 0;
    }
    <div class="card">
        <div class="card-body">
            <div class="d-flex" style="justify-content:space-between;align-items:center">
                <span style="font-weight:600;font-size:0.9rem">Checklist Progress</span>
                <span class="text-sm text-muted">@completed / @total</span>
            </div>
            <div class="progress-bar-container">
                <div class="progress-bar-fill @(pct >= 80 ? "good" : pct >= 50 ? "warn" : "bad")"
                     style="width:@(pct)%"></div>
            </div>
        </div>
    </div>

    @* Checklist grouped by category *@
    @foreach (var group in inspection.ChecklistItems.GroupBy(c => c.Category))
    {
        <div class="checklist-category">
            <div class="checklist-category-header">@group.Key</div>
            @foreach (var item in group)
            {
                <div class="checklist-item-wrapper">
                    <div class="checklist-item">
                        <span class="checklist-item-label">@item.Label</span>
                        <div class="check-buttons">
                            <button class="check-btn @(item.Result == CheckResult.Pass ? "pass" : "")"
                                    @onclick="() => SetResult(item, CheckResult.Pass)" title="Pass">✓</button>
                            <button class="check-btn @(item.Result == CheckResult.Fail ? "fail" : "")"
                                    @onclick="() => SetResult(item, CheckResult.Fail)" title="Fail">✗</button>
                            <button class="check-btn @(item.Result == CheckResult.NotApplicable ? "na" : "")"
                                    @onclick="() => SetResult(item, CheckResult.NotApplicable)" title="N/A">—</button>
                        </div>
                    </div>
                    @if (item.Result == CheckResult.Fail)
                    {
                        <div style="padding:0 0 0.5rem 0">
                            <textarea class="checklist-item-notes" @bind="item.Notes" @bind:event="oninput"
                                      placeholder="Describe the issue..." rows="2"></textarea>
                        </div>
                    }
                </div>
            }
        </div>
    }

    @* Photos section *@
    <div class="section-header">Photos</div>
    <div class="card">
        <div class="card-body">
            <div class="photo-grid">
                @foreach (var photo in inspection.Photos)
                {
                    <div class="photo-thumb">
                        <img src="data:image/jpeg;base64,@photo.DataBase64" alt="@photo.Caption" @onclick="() => ViewPhoto(photo)" />
                        <button class="remove-photo" @onclick="() => RemovePhoto(photo)" @onclick:stopPropagation="true">✗</button>
                    </div>
                }
                <label class="add-photo-btn">
                    <span class="icon">📷</span>
                    <span>Add</span>
                    <InputFile OnChange="OnPhotoSelected" accept="image/*" capture="environment"
                               style="display:none" />
                </label>
            </div>
        </div>
    </div>

    @* Complete button *@
    <div class="px-1 mt-1 mb-1">
        <button class="btn-primary-custom" @onclick="SaveAndComplete">
            ✅ Complete Inspection
        </button>
    </div>
}

@* Photo viewer modal *@
@if (viewingPhoto != null)
{
    <div class="photo-modal-overlay" @onclick="() => viewingPhoto = null">
        <button class="photo-modal-close">✗</button>
        <img src="data:image/jpeg;base64,@viewingPhoto.DataBase64" alt="@viewingPhoto.Caption" />
        @if (!string.IsNullOrEmpty(viewingPhoto.Caption))
        {
            <div class="photo-modal-caption">@viewingPhoto.Caption</div>
        }
    </div>
}

@code {
    [Parameter] public string SiteId { get; set; } = "";

    private Site? site;
    private Inspection inspection = new();
    private Photo? viewingPhoto;
    private Timer? autoSaveTimer;

    protected override async Task OnInitializedAsync()
    {
        site = await Db.GetSiteAsync(SiteId);
        if (site == null)
        {
            Nav.NavigateTo("/");
            return;
        }

        inspection.SiteId = site.Id;
        inspection.SiteName = site.Name;
        inspection.ChecklistItems = ChecklistTemplateService.GetDefaultChecklist();

        // Auto-save every 30 seconds
        autoSaveTimer = new Timer(async _ =>
        {
            await SaveDraft();
            await InvokeAsync(StateHasChanged);
        }, null, TimeSpan.FromSeconds(30), TimeSpan.FromSeconds(30));
    }

    private void SetResult(ChecklistItem item, CheckResult result)
    {
        // Toggle off if tapping the same result
        item.Result = item.Result == result ? CheckResult.NotChecked : result;
    }

    private async Task OnPhotoSelected(InputFileChangeEventArgs e)
    {
        foreach (var file in e.GetMultipleFiles(5))
        {
            try
            {
                // Read and resize to max 1200px, compress as JPEG
                var buffer = new byte[file.Size];
                await using var stream = file.OpenReadStream(maxAllowedSize: 10 * 1024 * 1024);
                await stream.ReadExactlyAsync(buffer);
                var base64 = Convert.ToBase64String(buffer);

                inspection.Photos.Add(new Photo
                {
                    DataBase64 = base64,
                    Caption = file.Name,
                    Timestamp = DateTime.UtcNow
                });
            }
            catch
            {
                // Skip files that can't be read
            }
        }
    }

    private void RemovePhoto(Photo photo) => inspection.Photos.Remove(photo);
    private void ViewPhoto(Photo photo) => viewingPhoto = photo;

    private async Task SaveDraft()
    {
        inspection.Status = InspectionStatus.InProgress;
        await Db.SaveInspectionAsync(inspection);
    }

    private async Task SaveAndComplete()
    {
        if (string.IsNullOrWhiteSpace(inspection.InspectorName))
        {
            inspection.InspectorName = "Inspector";
        }
        inspection.Status = InspectionStatus.Completed;
        inspection.Date = DateTime.UtcNow;
        await Db.SaveInspectionAsync(inspection);
        Nav.NavigateTo($"sites/{SiteId}");
    }

    private async void GoBack()
    {
        await SaveDraft();
        Nav.NavigateTo($"sites/{SiteId}");
    }

    public void Dispose() => autoSaveTimer?.Dispose();
}
```

