### Services/SyncService.cs
Background sync when connectivity returns.

```csharp
namespace SiteInspector.Services;

public class SyncService : IDisposable
{
    private readonly IndexedDbService _db;
    private readonly ConnectivityService _connectivity;
    private readonly HttpClient _http;
    private readonly ILogger<SyncService> _logger;

    public int PendingSyncCount { get; private set; }
    public bool IsSyncing { get; private set; }
    public event Action? OnSyncStateChanged;

    public SyncService(IndexedDbService db, ConnectivityService connectivity, HttpClient http, ILogger<SyncService> logger)
    {
        _db = db;
        _connectivity = connectivity;
        _http = http;
        _logger = logger;
        _connectivity.OnConnectivityChanged += HandleConnectivityChanged;
    }

    private async void HandleConnectivityChanged(bool isOnline)
    {
        if (isOnline)
            await SyncAsync();
    }

    public async Task SyncAsync()
    {
        if (IsSyncing || !_connectivity.IsOnline) return;

        IsSyncing = true;
        OnSyncStateChanged?.Invoke();

        try
        {
            var unsynced = await _db.GetUnsyncedInspectionsAsync();
            PendingSyncCount = unsynced.Count;
            OnSyncStateChanged?.Invoke();

            foreach (var inspection in unsynced)
            {
                try
                {
                    // In production, POST to a real API endpoint
                    // For now, simulate sync with a delay
                    var response = await _http.PostAsJsonAsync("api/inspections/sync", inspection);

                    if (response.IsSuccessStatusCode)
                    {
                        inspection.IsSynced = true;
                        await _db.SaveInspectionAsync(inspection);
                        PendingSyncCount--;
                        OnSyncStateChanged?.Invoke();
                    }
                }
                catch (HttpRequestException)
                {
                    // Server unreachable — will retry on next sync
                    _logger.LogWarning("Failed to sync inspection {Id}, will retry", inspection.Id);
                }
            }
        }
        finally
        {
            IsSyncing = false;
            OnSyncStateChanged?.Invoke();
        }
    }

    public async Task UpdatePendingCountAsync()
    {
        var unsynced = await _db.GetUnsyncedInspectionsAsync();
        PendingSyncCount = unsynced.Count;
        OnSyncStateChanged?.Invoke();
    }

    public void Dispose()
    {
        _connectivity.OnConnectivityChanged -= HandleConnectivityChanged;
    }
}
```

