## Services

Create a `Services/` directory:

### Services/IndexedDbService.cs
This service wraps JS interop calls to IndexedDB. It stores/retrieves Sites and Inspections as JSON.

```csharp
namespace SiteInspector.Services;

using Microsoft.JSInterop;
using SiteInspector.Models;
using System.Text.Json;

public class IndexedDbService
{
    private readonly IJSRuntime _js;
    private readonly JsonSerializerOptions _jsonOptions = new() { PropertyNamingPolicy = JsonNamingPolicy.CamelCase };

    public IndexedDbService(IJSRuntime js) => _js = js;

    // Sites
    public async Task<List<Site>> GetAllSitesAsync()
    {
        var json = await _js.InvokeAsync<string>("indexedDb.getAll", "sites");
        return JsonSerializer.Deserialize<List<Site>>(json, _jsonOptions) ?? new();
    }

    public async Task<Site?> GetSiteAsync(string id)
    {
        var json = await _js.InvokeAsync<string>("indexedDb.get", "sites", id);
        return string.IsNullOrEmpty(json) ? null : JsonSerializer.Deserialize<Site>(json, _jsonOptions);
    }

    public async Task SaveSiteAsync(Site site)
    {
        var json = JsonSerializer.Serialize(site, _jsonOptions);
        await _js.InvokeVoidAsync("indexedDb.put", "sites", json);
    }

    public async Task DeleteSiteAsync(string id)
    {
        await _js.InvokeVoidAsync("indexedDb.delete", "sites", id);
    }

    // Inspections
    public async Task<List<Inspection>> GetInspectionsForSiteAsync(string siteId)
    {
        var json = await _js.InvokeAsync<string>("indexedDb.getByIndex", "inspections", "siteId", siteId);
        return JsonSerializer.Deserialize<List<Inspection>>(json, _jsonOptions) ?? new();
    }

    public async Task<Inspection?> GetInspectionAsync(string id)
    {
        var json = await _js.InvokeAsync<string>("indexedDb.get", "inspections", id);
        return string.IsNullOrEmpty(json) ? null : JsonSerializer.Deserialize<Inspection>(json, _jsonOptions);
    }

    public async Task SaveInspectionAsync(Inspection inspection)
    {
        var json = JsonSerializer.Serialize(inspection, _jsonOptions);
        await _js.InvokeVoidAsync("indexedDb.put", "inspections", json);
    }

    public async Task DeleteInspectionAsync(string id)
    {
        await _js.InvokeVoidAsync("indexedDb.delete", "inspections", id);
    }

    public async Task<List<Inspection>> GetUnsyncedInspectionsAsync()
    {
        var json = await _js.InvokeAsync<string>("indexedDb.getByIndex", "inspections", "isSynced", false);
        return JsonSerializer.Deserialize<List<Inspection>>(json, _jsonOptions) ?? new();
    }
}
```

