### wwwroot/js/indexedDb.js
Full IndexedDB implementation:

```javascript
window.indexedDb = {
    db: null,
    DB_NAME: 'SiteInspectorDb',
    DB_VERSION: 1,

    async open() {
        if (this.db) return this.db;

        return new Promise((resolve, reject) => {
            const request = window.indexedDB.open(this.DB_NAME, this.DB_VERSION);

            request.onupgradeneeded = (event) => {
                const db = event.target.result;

                if (!db.objectStoreNames.contains('sites')) {
                    db.createObjectStore('sites', { keyPath: 'id' });
                }

                if (!db.objectStoreNames.contains('inspections')) {
                    const store = db.createObjectStore('inspections', { keyPath: 'id' });
                    store.createIndex('siteId', 'siteId', { unique: false });
                    store.createIndex('isSynced', 'isSynced', { unique: false });
                }
            };

            request.onsuccess = (event) => {
                this.db = event.target.result;
                resolve(this.db);
            };

            request.onerror = (event) => {
                reject(event.target.error);
            };
        });
    },

    async getAll(storeName) {
        const db = await this.open();
        return new Promise((resolve, reject) => {
            const tx = db.transaction(storeName, 'readonly');
            const store = tx.objectStore(storeName);
            const request = store.getAll();
            request.onsuccess = () => resolve(JSON.stringify(request.result));
            request.onerror = () => reject(request.error);
        });
    },

    async get(storeName, id) {
        const db = await this.open();
        return new Promise((resolve, reject) => {
            const tx = db.transaction(storeName, 'readonly');
            const store = tx.objectStore(storeName);
            const request = store.get(id);
            request.onsuccess = () => resolve(request.result ? JSON.stringify(request.result) : '');
            request.onerror = () => reject(request.error);
        });
    },

    async put(storeName, jsonData) {
        const db = await this.open();
        const data = JSON.parse(jsonData);
        return new Promise((resolve, reject) => {
            const tx = db.transaction(storeName, 'readwrite');
            const store = tx.objectStore(storeName);
            const request = store.put(data);
            request.onsuccess = () => resolve();
            request.onerror = () => reject(request.error);
        });
    },

    async delete(storeName, id) {
        const db = await this.open();
        return new Promise((resolve, reject) => {
            const tx = db.transaction(storeName, 'readwrite');
            const store = tx.objectStore(storeName);
            const request = store.delete(id);
            request.onsuccess = () => resolve();
            request.onerror = () => reject(request.error);
        });
    },

    async getByIndex(storeName, indexName, value) {
        const db = await this.open();
        return new Promise((resolve, reject) => {
            const tx = db.transaction(storeName, 'readonly');
            const store = tx.objectStore(storeName);
            const index = store.index(indexName);
            const request = index.getAll(value);
            request.onsuccess = () => resolve(JSON.stringify(request.result));
            request.onerror = () => reject(request.error);
        });
    }
};
