            <div class="stat-value" style="color:var(--na-color)">@na</div>
            <div class="stat-label">N/A</div>
        </div>
        <div class="stat-box">
            <div class="stat-value">@unchecked_</div>
            <div class="stat-label">Skipped</div>
        </div>
    </div>

    @* Checklist results *@
    <div class="section-header">Checklist Results</div>
    @foreach (var group in inspection.ChecklistItems.GroupBy(c => c.Category))
    {
        <div class="checklist-category">
            <div class="checklist-category-header">@group.Key</div>
            @foreach (var item in group)
            {
                <div class="checklist-item">
                    <span style="font-size:1.1rem;flex-shrink:0">
                        @switch (item.Result)
                        {
                            case CheckResult.Pass: <text>✅</text> break;
                            case CheckResult.Fail: <text>❌</text> break;
                            case CheckResult.NotApplicable: <text>⬜</text> break;
                            default: <text>⬜</text> break;
                        }
                    </span>
