@code {
    private List<Inspection>? inspections;

    protected override async Task OnInitializedAsync()
    {
        // Get all sites, then get all inspections
        var sites = await Db.GetAllSitesAsync();
        inspections = new();
        foreach (var site in sites)
        {
            var siteInspections = await Db.GetInspectionsForSiteAsync(site.Id);
            inspections.AddRange(siteInspections);
