+window.connectivity = {
+    dotNetRef: null,
+
+    initialize(dotNetRef) {
+        this.dotNetRef = dotNetRef;
+
+        window.addEventListener('online', () => {
+            this.dotNetRef.invokeMethodAsync('UpdateStatus', true);
+        });
+
+        window.addEventListener('offline', () => {
+            this.dotNetRef.invokeMethodAsync('UpdateStatus', false);
+        });
+
+        return navigator.onLine;
+    },
+
+    dispose() {
+        this.dotNetRef = null;
+    }
+};
+

