/* ===== GLOBAL ===== */
:root {
    --primary: #e94560;
    --primary-dark: #c73e54;
    --bg: #f5f5f5;
    --card-bg: #ffffff;
    --text: #1a1a2e;
    --text-muted: #6c757d;
    --border: #dee2e6;
    --success: #28a745;
    --warning: #ffc107;
    --danger: #dc3545;
    --na-color: #6c757d;
    --shadow: 0 2px 8px rgba(0,0,0,0.1);
}

*, *::before, *::after { box-sizing: border-box; }

html, body {
    margin: 0;
    padding: 0;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
    background: var(--bg);
    color: var(--text);
    font-size: 16px;
    -webkit-tap-highlight-color: transparent;
    overscroll-behavior: none;
}

/* Loading screen */
.loading-screen {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 100vh;
    gap: 1rem;
}
.loading-icon { font-size: 3rem; }
.loading-text { font-size: 1.1rem; color: var(--text-muted); }

/* ===== LAYOUT ===== */
.page { padding-bottom: 5rem; }

.top-bar {
    position: sticky;
    top: 0;
    z-index: 100;
    background: var(--primary);
    color: white;
    padding: 0.75rem 1rem;
    display: flex;
    align-items: center;
    gap: 0.75rem;
    box-shadow: var(--shadow);
}

.top-bar h1 {
    font-size: 1.2rem;
    margin: 0;
    font-weight: 600;
    flex: 1;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.top-bar .back-btn {
    background: none;
    border: none;
    color: white;
    font-size: 1.5rem;
    padding: 0;
    cursor: pointer;
    line-height: 1;
    display: flex;
    align-items: center;
}

/* Bottom nav */
.bottom-nav {
    position: fixed;
    bottom: 0;
    left: 0;
    right: 0;
    background: white;
    border-top: 1px solid var(--border);
    display: flex;
    z-index: 100;
    box-shadow: 0 -2px 8px rgba(0,0,0,0.08);
    padding-bottom: env(safe-area-inset-bottom, 0);
}

.bottom-nav a {
    flex: 1;
    display: flex;
    flex-direction: column;
    align-items: center;
    padding: 0.5rem 0;
    text-decoration: none;
    color: var(--text-muted);
    font-size: 0.7rem;
    gap: 0.2rem;
    transition: color 0.15s;
}

.bottom-nav a.active {
    color: var(--primary);
}

.bottom-nav .nav-icon {
    font-size: 1.4rem;
    line-height: 1;
}

/* ===== CARDS ===== */
.card {
    background: var(--card-bg);
    border-radius: 12px;
    box-shadow: var(--shadow);
    margin: 0.75rem 1rem;
    overflow: hidden;
    border: none;
}

.card-body { padding: 1rem; }

.card-header {
    background: transparent;
    border-bottom: 1px solid var(--border);
    padding: 0.75rem 1rem;
    font-weight: 600;
    font-size: 0.95rem;
}

/* ===== BUTTONS ===== */
.btn-primary-custom {
    background: var(--primary);
    color: white;
    border: none;
    border-radius: 10px;
    padding: 0.85rem 1.5rem;
    font-size: 1rem;
    font-weight: 600;
    cursor: pointer;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 0.5rem;
    width: 100%;
    transition: background 0.15s;
    -webkit-appearance: none;
}

.btn-primary-custom:active {
    background: var(--primary-dark);
    transform: scale(0.98);
}

.btn-outline {
    background: transparent;
    color: var(--primary);
    border: 2px solid var(--primary);
    border-radius: 10px;
    padding: 0.75rem 1.5rem;
    font-size: 1rem;
    font-weight: 600;
    cursor: pointer;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 0.5rem;
    width: 100%;
    transition: all 0.15s;
}

.btn-outline:active {
    background: var(--primary);
    color: white;
}

.btn-danger-custom {
    background: var(--danger);
    color: white;
    border: none;
    border-radius: 10px;
    padding: 0.75rem 1.5rem;
    font-size: 0.9rem;
    font-weight: 600;
    cursor: pointer;
    width: 100%;
}

.btn-small {
    padding: 0.4rem 0.8rem;
    font-size: 0.85rem;
    border-radius: 8px;
    width: auto;
}

/* ===== FORMS ===== */
.form-group {
    margin-bottom: 1rem;
}

.form-group label {
    display: block;
    font-weight: 600;
    font-size: 0.85rem;
    margin-bottom: 0.4rem;
    color: var(--text-muted);
    text-transform: uppercase;
    letter-spacing: 0.03em;
}

.form-input {
    width: 100%;
    padding: 0.75rem;
    border: 2px solid var(--border);
    border-radius: 10px;
    font-size: 1rem;
    background: white;
    color: var(--text);
    -webkit-appearance: none;
    transition: border-color 0.15s;
}

.form-input:focus {
    outline: none;
    border-color: var(--primary);
}

textarea.form-input {
    min-height: 80px;
    resize: vertical;
}

/* ===== CHECKLIST ===== */
.checklist-category {
    margin: 0.75rem 1rem;
}

.checklist-category-header {
    font-weight: 700;
    font-size: 0.85rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: var(--text-muted);
    padding: 0.5rem 0;
    border-bottom: 2px solid var(--border);
    margin-bottom: 0.25rem;
}

.checklist-item {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.75rem 0;
    border-bottom: 1px solid #f0f0f0;
    min-height: 52px;
}

.checklist-item-label {
    flex: 1;
    font-size: 0.95rem;
    line-height: 1.3;
}

.check-buttons {
    display: flex;
    gap: 0.3rem;
    flex-shrink: 0;
}

.check-btn {
    width: 40px;
    height: 40px;
    border-radius: 8px;
    border: 2px solid var(--border);
    background: white;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 1.1rem;
    transition: all 0.1s;
    padding: 0;
    -webkit-appearance: none;
}

.check-btn:active { transform: scale(0.9); }
.check-btn.pass { background: var(--success); border-color: var(--success); color: white; }
.check-btn.fail { background: var(--danger); border-color: var(--danger); color: white; }
.check-btn.na { background: var(--na-color); border-color: var(--na-color); color: white; }

.checklist-item-notes {
    width: 100%;
    padding: 0.5rem;
    border: 1px solid var(--border);
    border-radius: 8px;
    font-size: 0.85rem;
    margin-top: 0.25rem;
    resize: none;
}

.checklist-item-wrapper {
    border-bottom: 1px solid #f0f0f0;
}

/* ===== INSPECTION LIST ===== */
.inspection-card {
    display: flex;
    align-items: center;
    padding: 1rem;
    gap: 0.75rem;
    cursor: pointer;
    transition: background 0.15s;
    text-decoration: none;
    color: inherit;
}

.inspection-card:active { background: #f0f0f0; }

.inspection-status-dot {
    width: 12px;
    height: 12px;
    border-radius: 50%;
    flex-shrink: 0;
}

.inspection-status-dot.completed { background: var(--success); }
.inspection-status-dot.in-progress { background: var(--warning); }

.inspection-info { flex: 1; min-width: 0; }
.inspection-info .date { font-weight: 600; font-size: 0.95rem; }
.inspection-info .inspector { font-size: 0.85rem; color: var(--text-muted); }

.sync-badge {
    font-size: 0.7rem;
    padding: 0.2rem 0.5rem;
    border-radius: 20px;
    font-weight: 600;
    flex-shrink: 0;
}
.sync-badge.synced { background: #d4edda; color: #155724; }
.sync-badge.pending { background: #fff3cd; color: #856404; }

/* ===== SITE LIST ===== */
.site-item {
    display: flex;
    align-items: center;
    padding: 1rem;
    gap: 0.75rem;
    text-decoration: none;
    color: inherit;
    border-bottom: 1px solid #f0f0f0;
    transition: background 0.15s;
}

.site-item:active { background: #f0f0f0; }
.site-item:last-child { border-bottom: none; }

.site-icon {
    width: 48px;
    height: 48px;
    background: #fff0f3;
    border-radius: 12px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 1.5rem;
    flex-shrink: 0;
}

.site-info { flex: 1; min-width: 0; }
.site-info .name {
    font-weight: 600;
    font-size: 1rem;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}
.site-info .address {
    font-size: 0.85rem;
    color: var(--text-muted);
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.site-chevron {
    color: var(--text-muted);
    font-size: 1.2rem;
}

/* ===== PHOTOS ===== */
.photo-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 0.5rem;
    padding: 0;
}

.photo-thumb {
    aspect-ratio: 1;
    border-radius: 8px;
    overflow: hidden;
    position: relative;
    cursor: pointer;
}

.photo-thumb img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.photo-thumb .remove-photo {
    position: absolute;
    top: 4px;
    right: 4px;
    width: 24px;
    height: 24px;
    background: rgba(220,53,69,0.9);
    color: white;
    border: none;
    border-radius: 50%;
    font-size: 0.8rem;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 0;
}

.add-photo-btn {
    aspect-ratio: 1;
    border: 2px dashed var(--border);
    border-radius: 8px;
    background: transparent;
    cursor: pointer;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 0.25rem;
    color: var(--text-muted);
    font-size: 0.75rem;
    padding: 0;
}

.add-photo-btn .icon { font-size: 1.5rem; }

/* ===== CONNECTIVITY BANNER ===== */
.connectivity-banner {
    padding: 0.4rem 1rem;
    text-align: center;
    font-size: 0.8rem;
    font-weight: 600;
}

.connectivity-banner.offline {
    background: var(--warning);
    color: #856404;
}

.connectivity-banner.syncing {
    background: #cce5ff;
    color: #004085;
}

/* ===== STATS ===== */
.stats-row {
    display: flex;
    gap: 0.5rem;
    padding: 0 1rem;
    margin-bottom: 0.5rem;
}

.stat-box {
    flex: 1;
    background: var(--card-bg);
    border-radius: 10px;
    padding: 0.75rem;
    text-align: center;
    box-shadow: var(--shadow);
}

.stat-value {
    font-size: 1.5rem;
    font-weight: 700;
    line-height: 1;
}

.stat-label {
    font-size: 0.7rem;
    color: var(--text-muted);
    text-transform: uppercase;
    letter-spacing: 0.03em;
    margin-top: 0.25rem;
}

/* ===== EMPTY STATE ===== */
.empty-state {
    text-align: center;
    padding: 3rem 2rem;
    color: var(--text-muted);
}

.empty-state .icon {
    font-size: 3rem;
    margin-bottom: 1rem;
}

.empty-state .title {
    font-size: 1.1rem;
    font-weight: 600;
    margin-bottom: 0.5rem;
    color: var(--text);
}

/* ===== PROGRESS BAR ===== */
.progress-bar-container {
    height: 6px;
    background: #e9ecef;
    border-radius: 3px;
    overflow: hidden;
    margin: 0.5rem 0;
}

.progress-bar-fill {
    height: 100%;
    border-radius: 3px;
    transition: width 0.3s;
}

.progress-bar-fill.good { background: var(--success); }
.progress-bar-fill.warn { background: var(--warning); }
.progress-bar-fill.bad { background: var(--danger); }

/* ===== FAB ===== */
.fab {
    position: fixed;
    bottom: 5.5rem;
    right: 1rem;
    width: 56px;
    height: 56px;
    border-radius: 50%;
    background: var(--primary);
    color: white;
    border: none;
    font-size: 1.5rem;
    cursor: pointer;
    box-shadow: 0 4px 12px rgba(233,69,96,0.4);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 50;
    transition: transform 0.15s;
}

.fab:active { transform: scale(0.9); }

/* ===== SECTION ===== */
.section-header {
    padding: 0.5rem 1rem;
    font-size: 0.8rem;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: var(--text-muted);
}

/* ===== UTILITIES ===== */
.px-1 { padding-left: 1rem; padding-right: 1rem; }
.mt-1 { margin-top: 1rem; }
.mb-1 { margin-bottom: 1rem; }
.gap-half { gap: 0.5rem; }
.d-flex { display: flex; }
.flex-col { flex-direction: column; }
.text-center { text-align: center; }
.text-muted { color: var(--text-muted); }
.text-sm { font-size: 0.85rem; }

/* ===== PHOTO VIEWER MODAL ===== */
.photo-modal-overlay {
    position: fixed;
    inset: 0;
    background: rgba(0,0,0,0.9);
    z-index: 200;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
}

.photo-modal-overlay img {
    max-width: 95vw;
    max-height: 80vh;
    object-fit: contain;
    border-radius: 8px;
}

.photo-modal-close {
    position: absolute;
    top: 1rem;
    right: 1rem;
    background: none;
    border: none;
    color: white;
    font-size: 2rem;
    cursor: pointer;
}

.photo-modal-caption {
    color: white;
    margin-top: 1rem;
    font-size: 0.9rem;
}

/* Hide Bootstrap nav - we use bottom nav */
.navbar { display: none !important; }

/* ===== BLAZOR ERROR UI ===== */
#blazor-error-ui {
    background: lightyellow;
    bottom: 0;
    box-shadow: 0 -1px 2px rgba(0, 0, 0, 0.2);
    display: none;
    left: 0;
    padding: 0.6rem 1.25rem 0.7rem 1.25rem;
    position: fixed;
    width: 100%;
    z-index: 1000;
}

#blazor-error-ui .dismiss {
    cursor: pointer;
    position: absolute;
    right: 0.75rem;
    top: 0.5rem;
}

.loading-progress {
    position: relative;
    display: block;
    width: 8rem;
    height: 8rem;
}

.loading-progress circle {
    fill: none;
    stroke: #e0e0e0;
    stroke-width: 0.6rem;
    transform-origin: 50% 50%;
    transform: rotate(-90deg);
}

.loading-progress circle:last-child {
    stroke: var(--primary, #e94560);
    stroke-dasharray: calc(3.14 * 80%), 500%;
    transition: stroke-dasharray 0.05s ease-in-out;
}

.loading-progress-text {
    position: absolute;
    text-align: center;
    font-weight: bold;
    inset: calc(20vh - 0.25rem) 0 auto 0.2rem;
}

.loading-progress-text:after {
    content: var(--blazor-load-percentage-text, "Loading");
}

