@inherits LayoutComponentBase
@inject ConnectivityService Connectivity
@inject SyncService Sync
@implements IDisposable

@if (!Connectivity.IsOnline)
{
    <div class="connectivity-banner offline">
        📡 Offline — data saves locally
    </div>
}
else if (Sync.IsSyncing)
{
    <div class="connectivity-banner syncing">
        🔄 Syncing @Sync.PendingSyncCount item(s)...
    </div>
}

<main class="page">
    @Body
</main>

<nav class="bottom-nav">
    <NavLink href="" Match="NavLinkMatch.All">
        <span class="nav-icon">🏗️</span>
        Sites
    </NavLink>
    <NavLink href="inspections" Match="NavLinkMatch.Prefix">
        <span class="nav-icon">📋</span>
        Inspections
    </NavLink>
</nav>

@code {
    protected override async Task OnInitializedAsync()
    {
        await Connectivity.InitializeAsync();
        Connectivity.OnConnectivityChanged += OnStatusChanged;
        Sync.OnSyncStateChanged += OnStatusChanged;
    }

    private void OnStatusChanged(bool _) => InvokeAsync(StateHasChanged);
    private void OnStatusChanged() => InvokeAsync(StateHasChanged);

    public void Dispose()
    {
        Connectivity.OnConnectivityChanged -= OnStatusChanged;
        Sync.OnSyncStateChanged -= OnStatusChanged;
    }
}

@page "/"
@inject IndexedDbService Db
@inject NavigationManager Nav

<div class="top-bar">
    <h1>🏗️ Site Inspector</h1>
</div>

<div class="section-header mt-1">Your Sites</div>

@if (sites == null)
{
    <div class="text-center mt-1 text-muted">Loading...</div>
}
else if (sites.Count == 0)
{
    <div class="empty-state">
        <div class="icon">🏗️</div>
        <div class="title">No construction sites yet</div>
        <p>Tap the + button to add your first site.</p>
    </div>
}
else
{
    <div class="card">
        @foreach (var site in sites)
        {
            <a class="site-item" href="@($"sites/{site.Id}")">
                <div class="site-icon">🏢</div>
                <div class="site-info">
                    <div class="name">@site.Name</div>
                    <div class="address">@site.Address</div>
                </div>
                <span class="site-chevron">›</span>
            </a>
        }
    </div>
}

<button class="fab" @onclick="GoToNewSite" aria-label="Add site">＋</button>

@code {
    private List<Site>? sites;

    protected override async Task OnInitializedAsync()
    {
        sites = await Db.GetAllSitesAsync();
        sites = sites.OrderByDescending(s => s.CreatedAt).ToList();
    }

    private void GoToNewSite() => Nav.NavigateTo("sites/new");
}

