@page "/sites/new"
@inject IndexedDbService Db
@inject NavigationManager Nav

<div class="top-bar">
    <button class="back-btn" @onclick='() => Nav.NavigateTo("/")'>‹</button>
    <h1>New Site</h1>
</div>

<div class="card">
    <div class="card-body">
        <div class="form-group">
            <label>Site Name</label>
            <input class="form-input" @bind="site.Name" placeholder="e.g. Riverside Tower Block A" />
        </div>
        <div class="form-group">
            <label>Address</label>
            <textarea class="form-input" @bind="site.Address" placeholder="Full site address" rows="2"></textarea>
        </div>
        <button class="btn-primary-custom" @onclick="Save" disabled="@saving">
            @(saving ? "Saving..." : "💾 Save Site")
        </button>
    </div>
</div>

@code {
    private Site site = new();
    private bool saving;

    private async Task Save()
    {
        if (string.IsNullOrWhiteSpace(site.Name)) return;
        saving = true;
        await Db.SaveSiteAsync(site);
        Nav.NavigateTo($"sites/{site.Id}");
    }
}

@page "/sites/{SiteId}"
@inject IndexedDbService Db
@inject NavigationManager Nav

@if (site == null)
{
    <div class="top-bar">
        <button class="back-btn" @onclick='() => Nav.NavigateTo("/")'>‹</button>
        <h1>Loading...</h1>
    </div>
}
else
{
    <div class="top-bar">
        <button class="back-btn" @onclick='() => Nav.NavigateTo("/")'>‹</button>
        <h1>@site.Name</h1>
    </div>

    <div class="card">
        <div class="card-body">
            <div class="text-sm text-muted">📍 @site.Address</div>
        </div>
    </div>

    @if (inspections.Count > 0)
    {
        <div class="stats-row">
            <div class="stat-box">
                <div class="stat-value">@inspections.Count</div>
                <div class="stat-label">Inspections</div>
            </div>
            <div class="stat-box">
                <div class="stat-value">@inspections.Count(i => i.Status == InspectionStatus.Completed)</div>
                <div class="stat-label">Completed</div>
            </div>
            <div class="stat-box">
                <div class="stat-value">@inspections.Count(i => i.IsSynced)</div>
                <div class="stat-label">Synced</div>
            </div>
        </div>
    }

    <div class="section-header">Inspections</div>

    @if (inspections.Count == 0)
    {
        <div class="empty-state">
            <div class="icon">📋</div>
            <div class="title">No inspections yet</div>
            <p>Tap the + button to start an inspection.</p>
        </div>
    }
    else
    {
        <div class="card">
            @foreach (var insp in inspections)
            {
                <a class="inspection-card" href="@($"inspections/{insp.Id}")">
                    <div class="inspection-status-dot @(insp.Status == InspectionStatus.Completed ? "completed" : "in-progress")"></div>
                    <div class="inspection-info">
                        <div class="date">@insp.Date.ToLocalTime().ToString("MMM d, yyyy h:mm tt")</div>
                        <div class="inspector">@insp.InspectorName</div>
                    </div>
                    <span class="sync-badge @(insp.IsSynced ? "synced" : "pending")">
                        @(insp.IsSynced ? "Synced" : "Pending")
                    </span>
                </a>
            }
        </div>
    }

    <button class="fab" @onclick="StartInspection" aria-label="New inspection">＋</button>
}

@code {
    [Parameter] public string SiteId { get; set; } = "";

    private Site? site;
    private List<Inspection> inspections = new();

    protected override async Task OnInitializedAsync()
    {
        site = await Db.GetSiteAsync(SiteId);
        if (site != null)
        {
            inspections = await Db.GetInspectionsForSiteAsync(SiteId);
            inspections = inspections.OrderByDescending(i => i.Date).ToList();
        }
    }

    private void StartInspection() => Nav.NavigateTo($"inspections/new/{SiteId}");
}

@page "/inspections/new/{SiteId}"
@inject IndexedDbService Db
@inject NavigationManager Nav
@implements IDisposable

<div class="top-bar">
    <button class="back-btn" @onclick="GoBack">‹</button>
    <h1>New Inspection</h1>
    <button class="back-btn" style="font-size:1rem" @onclick="SaveAndComplete">✓</button>
</div>

@if (site == null)
{
    <div class="text-center mt-1 text-muted">Loading...</div>
}
else
{
    <div class="card">
        <div class="card-body">
            <div class="form-group">
                <label>Inspector Name</label>
                <input class="form-input" @bind="inspection.InspectorName" @bind:event="oninput" placeholder="Your name" />
            </div>
            <div class="form-group">
                <label>General Notes</label>
                <textarea class="form-input" @bind="inspection.Notes" @bind:event="oninput" placeholder="Overall observations..." rows="3"></textarea>
            </div>
        </div>
    </div>

    @* Progress *@
    @{
        var total = inspection.ChecklistItems.Count;
        var completed = inspection.ChecklistItems.Count(c => c.Result != CheckResult.NotChecked);
        var pct = total > 0 ? (int)(100.0 * completed / total) : 0;
    }
    <div class="card">
        <div class="card-body">
            <div class="d-flex" style="justify-content:space-between;align-items:center">
                <span style="font-weight:600;font-size:0.9rem">Checklist Progress</span>
                <span class="text-sm text-muted">@completed / @total</span>
            </div>
            <div class="progress-bar-container">
                <div class="progress-bar-fill @(pct >= 80 ? "good" : pct >= 50 ? "warn" : "bad")"
                     style="width:@(pct)%"></div>
            </div>
        </div>
    </div>

    @* Checklist grouped by category *@
    @foreach (var group in inspection.ChecklistItems.GroupBy(c => c.Category))
    {
        <div class="checklist-category">
            <div class="checklist-category-header">@group.Key</div>
            @foreach (var item in group)
            {
                <div class="checklist-item-wrapper">
                    <div class="checklist-item">
                        <span class="checklist-item-label">@item.Label</span>
                        <div class="check-buttons">
                            <button class="check-btn @(item.Result == CheckResult.Pass ? "pass" : "")"
                                    @onclick="() => SetResult(item, CheckResult.Pass)" title="Pass">✓</button>
                            <button class="check-btn @(item.Result == CheckResult.Fail ? "fail" : "")"
                                    @onclick="() => SetResult(item, CheckResult.Fail)" title="Fail">✗</button>
                            <button class="check-btn @(item.Result == CheckResult.NotApplicable ? "na" : "")"
                                    @onclick="() => SetResult(item, CheckResult.NotApplicable)" title="N/A">—</button>
                        </div>
                    </div>
                    @if (item.Result == CheckResult.Fail)
                    {
                        <div style="padding:0 0 0.5rem 0">
                            <textarea class="checklist-item-notes" @bind="item.Notes" @bind:event="oninput"
                                      placeholder="Describe the issue..." rows="2"></textarea>
                        </div>
                    }
                </div>
            }
        </div>
    }

    @* Photos section *@
    <div class="section-header">Photos</div>
    <div class="card">
        <div class="card-body">
